// It returns an instance of *GRPCServer which callers can Run().
func NewGRPCServer(
	ctx context.Context,
	logger *zap.Logger,
	cfg *config.Config,
	ipch *inprocgrpc.Channel,
	info info.Flipt,
	licenseManager license.Manager,
	secretsManager secrets.Manager,
	opts ...GRPCServerOption,
